-- ================================================================
-- CFP Bracket Mode — migration
-- Run in Supabase SQL Editor after full_season_migration.sql
-- ================================================================

-- cfp_brackets: one per full_season_session
-- seedings: JSON array of 12 seeded teams (generated by ranking algo)
-- cfp_rankings: JSON array of full ranked list for display

create table if not exists public.cfp_brackets (
  id            uuid primary key default uuid_generate_v4(),
  session_id    uuid not null references public.full_season_sessions(id) on delete cascade,
  season        integer not null,
  seedings      jsonb not null default '[]'::jsonb,
  cfp_rankings  jsonb not null default '[]'::jsonb,
  is_customized boolean not null default false,
  created_at    timestamptz not null default now(),
  updated_at    timestamptz not null default now(),
  unique(session_id)
);

create index if not exists idx_cfpb_session on public.cfp_brackets(session_id);

-- cfp_picks: one per (bracket, round, game_index)
-- round:      1 = first round (4 games)
--             2 = quarterfinals (4 games)
--             3 = semifinals (2 games)
--             4 = championship (1 game)
-- game_index: 0-based within the round

create table if not exists public.cfp_picks (
  id              uuid primary key default uuid_generate_v4(),
  bracket_id      uuid not null references public.cfp_brackets(id) on delete cascade,
  round           integer not null check (round between 1 and 4),
  game_index      integer not null check (game_index >= 0),
  winner_team_id  uuid not null references public.teams(id),
  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now(),
  unique(bracket_id, round, game_index)
);

create index if not exists idx_cfpp_bracket on public.cfp_picks(bracket_id);

-- ── Row Level Security ────────────────────────────────────────────

alter table public.cfp_brackets enable row level security;
alter table public.cfp_picks    enable row level security;

create policy "cfpb_all_own" on public.cfp_brackets
  for all using (
    exists (
      select 1 from public.full_season_sessions
      where id = session_id and user_id = auth.uid()
    )
  );

create policy "cfpp_all_own" on public.cfp_picks
  for all using (
    exists (
      select 1 from public.cfp_brackets cb
      join public.full_season_sessions fss on fss.id = cb.session_id
      where cb.id = bracket_id and fss.user_id = auth.uid()
    )
  );
